import React, { Fragment, useEffect, useState } from 'react'
import { Card, CardBody, CardHeader, Col, Container, FormGroup, Input, Label, Row } from 'reactstrap';
import Breadcrumb from '../components/common/Breadcrumb';
import {postFetch,getFetch} from '../config/fetchData';
const AddNode = () => {
    const [methods,setMethods] = useState([]);
    const [method,setMethod] = useState();
    useEffect(()=>{
        if(methods.length==0){
            getFetch(`/Method/all`).then((data)=>{console.log(data);})
        }
    },[])
    return (
        <Fragment>
            <Breadcrumb title="Create Node" parent="Nodes" />
            <Container fluid={true}>
                <Row className="product-adding">
                    <Col xl="6">
                        <Card>
                            <CardHeader>
                                <h5>General</h5>
                            </CardHeader>
                            <CardBody>
                                <div className="digital-add needs-validation">
                                    <FormGroup>
                                        <Label className="col-form-label">
                                            <span>*</span> Method
                                        </Label>
                                        <select className="custom-select" required="" name='method'>
                                            <option value="null">--Select--</option>

                                        </select>
                                    </FormGroup>
                                </div>
                            </CardBody>
                        </Card>
                    </Col>
                </Row>
            </Container>
        </Fragment>
    )
}

export default AddNode
